CREATE TABLE IF NOT EXISTS notifications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, user_id UUID NOT NULL, channel VARCHAR(20) NOT NULL, type VARCHAR(50) NOT NULL, title JSONB DEFAULT '{}', body JSONB DEFAULT '{}', data JSONB DEFAULT '{}', read_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW()); CREATE TABLE IF NOT EXISTS notification_preferences (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, user_id UUID NOT NULL UNIQUE, email BOOLEAN DEFAULT TRUE, sms BOOLEAN DEFAULT TRUE, push BOOLEAN DEFAULT TRUE, in_app BOOLEAN DEFAULT TRUE, order_updates BOOLEAN DEFAULT TRUE, promotions BOOLEAN DEFAULT FALSE, digest VARCHAR(20) DEFAULT 'instant', updated_at TIMESTAMPTZ DEFAULT NOW());
